import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{n as i,t as a}from"./chunks/template-generator-advanced.CleIDHrl.js";import{n as o,t as s}from"./chunks/gradle-prompt.DgUqZl-T.js";const c=JSON.parse(`{"title":"创建项目","description":"关于如何使用 Fabric 模板模组生成器创建新的模组项目的逐步指南。","frontmatter":{"title":"创建项目","description":"关于如何使用 Fabric 模板模组生成器创建新的模组项目的逐步指南。","authors":["IMB11"],"search":false,"files":[]},"headers":[],"relativePath":"zh_cn/1.20.4/develop/getting-started/creating-a-project.md","filePath":"versions/1.20.4/translated/zh_cn/develop/getting-started/creating-a-project.md","lastUpdated":1739538073000}`);var l={name:`zh_cn/1.20.4/develop/getting-started/creating-a-project.md`};function u(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">创建项目 <a class="header-anchor" href="#h1" aria-label="Permalink to “创建项目”">​</a></h1><p>Fabric 提供了一种简单的方法来使用 Fabric 模板模组生成器来创建新的模组项目——如果你愿意，你可以使用示例模组代码仓库手动创建一个新项目，请参考<a href="#manual-project-creation">手动创建项目</a>章节。</p><h2 id="generating-a-project" tabindex="-1">生成项目 <a class="header-anchor" href="#generating-a-project" aria-label="Permalink to “生成项目”">​</a></h2><p>你可以使用 <a href="https://fabricmc.net/develop/template/" target="_blank" rel="noreferrer">Fabric 模板模组生成器</a>为你的模组生成一个新项目——你应该填写必要的字段，比如包名和模组名称，以及你想要基于开发的 Minecraft 版本。</p><p><img src="/assets/develop/getting-started/template-generator.png" alt="生成器预览图" loading="lazy"></p><p>如果你想要使用 Kotlin 语言开发，或者想要添加数据生成器，可以在&quot;Advanced Options&quot;部分中选择对应的选项。</p><p><img src="/assets/develop/getting-started/template-generator-advanced.png" alt="&quot;Advanced Options&quot;部分" loading="lazy"></p><p>填写好了必需的字段后，单击&quot;Generate&quot;按钮，生成器将以 zip 文件的形式创建新项目供你使用。</p><p>你需要将这个 zip 文件解压到你想要的位置，然后在 IntelliJ IDEA 中打开解压的文件夹:</p><p><img src="/assets/develop/getting-started/open-project.png" alt="打开项目按钮提示" loading="lazy"></p><h2 id="importing-the-project" tabindex="-1">导入项目 <a class="header-anchor" href="#importing-the-project" aria-label="Permalink to “导入项目”">​</a></h2><p>你在 IntelliJ IDEA 中打开了项目之后，IDEA 会自动加载项目的 Gradle 配置并执行必要的初始化任务。</p><p>如果收到一个关于 Gradle 构建脚本的通知，应该点击 <code>Import Gradle Project</code> 按钮：</p><p><img src="/assets/develop/getting-started/gradle-prompt.png" alt="Gradle 按钮提示" loading="lazy"></p><p>项目导入好之后，你可以在项目资源管理器中看到项目的文件，就能够开始开发你的模组了。</p><h2 id="manual-project-creation" tabindex="-1">手动创建项目 <a class="header-anchor" href="#manual-project-creation" aria-label="Permalink to “手动创建项目”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>你需要安装 <a href="https://git-scm.com/" target="_blank" rel="noreferrer">Git</a> 来克隆示例模组代码仓库。</p></div><p>如果不能使用 Fabric 模板模组生成器，可以按以下步骤手动创建新项目。</p><p>首先，使用 Git 克隆示例模组代码仓库：</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/FabricMC/fabric-example-mod/</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-mod-project</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这会将代码仓库克隆进一个叫 <code>my-mod-project</code>的新文件夹。</p><p>然后，您应该删除<code>.git</code>文件夹，并在IntelliJ IDEA中打开项目。 如果你找不到<code>.git</code>文件夹，你需要在你的文件资源管理器中启用显示隐藏文件。 如果你找不到<code>.git</code>文件夹，你需要在你的文件资源管理器中启用显示隐藏文件。 如果 <code>.git</code> 文件夹没有出现，需要在你的文件资源管理器中启用显示隐藏文件。</p><p>在 IntelliJ IDEA 中打开了项目之后，IDEA 会自动加载项目的 Gradle 配置并执行必要的初始化任务。</p><p>强调一遍，如上所述，如果你收到一个关于 Gradle 构建脚本的通知，你应该点击 <code>Import Gradle Project</code> 按钮：</p><h3 id="modifying-the-template" tabindex="-1">修改模板 <a class="header-anchor" href="#modifying-the-template" aria-label="Permalink to “修改模板”">​</a></h3><p>项目导入好后，你需要修改项目的细节，以匹配你的模组的信息:</p><ul><li>修改项目的 <code>gradle.properties</code> 文件，把 <code>maven_group</code> 和 <code>archive_base_name</code> 修改为匹配你的模组的信息。</li><li>修改项目中的 <code>fabric.mod.json</code> 文件，把 <code>id</code>、<code>name</code> 和 <code>description</code> 修改为匹配你的模组的信息。</li><li>确保修改你的项目的Minecraft的版本，映射，Fabric模组加载器和Fabric loom——所有这些都可以通过<a href="https://fabricmc.net/develop/%E6%9F%A5%E8%AF%A2%EF%BC%8C%E4%BB%A5%E5%8C%B9%E9%85%8D%E6%82%A8%E5%B8%8C%E6%9C%9B%E7%9A%84%E7%9B%AE%E6%A0%87%E7%89%88%E6%9C%AC%E3%80%82" target="_blank" rel="noreferrer">https://fabricmc.net/develop/查询，以匹配您希望的目标版本。</a></li></ul><p>你还可以修改包名和模组的主类来匹配你的模组的细节。</p>`,28)]])}var d=r(l,[[`render`,u]]);export{c as __pageData,d as default};